275	    <tr><td>Total leads</td><td colspan="3">${data.leads.length}</td></tr>
276	    <tr><td>Decision changes</td><td colspan="3" style="color:#ebcb8b"><b>${m.changed_decision_count}</b></td></tr>`;
277	
278	  // Distribution
279	  const decisions = ['DRAFT_NOW','WATCH','MAYBE','REJECT'];
280	  const distBody = document.querySelector('#distTable tbody');
281	  distBody.innerHTML = decisions.map(d => {
282	    const b = m.distribution_before[d]||0;
283	    const a = m.distribution_after[d]||0;
284	    const dlt = a-b;
285	    return `<tr><td>${badge(d)}</td><td>${b}</td><td>${a}</td>
286	            <td class="${dlt>0?'up':dlt<0?'dn':''}">${dlt>0?'+':''}${dlt}</td></tr>`;
287	  }).join('');
288	
289	  // Calibration
290	  const calBody = document.querySelector('#calTable tbody');
291	  calBody.innerHTML = decisions.map(d => {
292	    const cnt = m.outcome_count_by_decision_before[d]||0;
293	    const wb = m.win_rate_by_decision_before[d];
294	    const wa = m.win_rate_by_decision_after[d];
295	    return `<tr><td>${badge(d)}</td><td>${cnt}</td>
296	            <td>${wb!=null?(wb*100).toFixed(0)+'%':'n/a'}</td>
297	            <td>${wa!=null?(wa*100).toFixed(0)+'%':'n/a'}</td></tr>`;
298	  }).join('');
299	
300	  // Top codes
301	  const codesBody = document.querySelector('#codesTable tbody');
302	  codesBody.innerHTML = (m.top_reason_codes||[]).map(([code,cnt]) =>
303	    `<tr><td><code>${code}</code></td><td>${cnt}</td></tr>`).join('');
304	
305	  // Changed decisions
306	  document.getElementById('changedCount').textContent = m.changed_decision_count;
307	  const changed = data.leads.filter(l => l.decision_changed);
308	  document.querySelector('#changesTable tbody').innerHTML = changed.map(l => {
309	    const dlt = l.delta;
310	    return `<tr><td>${l.id}</td><td title="${l.title}">${l.title.substring(0,35)}</td>
311	            <td>${badge(l.old_decision)}</td><td>${badge(l.new_decision)}</td>
312	            <td class="${dlt>=0?'up':'dn'}">${dlt>=0?'+':''}${dlt}</td>
313	            <td style="font-size:10px">${l.outcome||''}</td></tr>`;
314	  }).join('');
315	
316	  // All leads
317	  const leadsBody = document.querySelector('#leadsTable tbody');
318	  leadsBody.innerHTML = data.leads.map(l => {
319	    const dlt = l.delta;
320	    const cls = l.decision_changed ? 'changed' : '';
321	    const oldScoreStr = l.old_score !== null ? l.old_score : '<span style="color:#5a6374">unsco.</span>';
322	    return `<tr class="${cls}">
323	      <td>${l.id}</td>
324	      <td title="${l.title}">${l.title.substring(0,32)}</td>
325	      <td>${oldScoreStr}</td>
326	      <td><b>${l.new_score}</b></td>
327	      <td class="${dlt>0?'up':dlt<0?'dn':''}">${dlt>0?'+':''}${dlt}</td>
328	      <td>${badge(l.old_decision)}</td>
329	      <td>${badge(l.new_decision)}</td>
330	      <td>${l.decision_changed?'<span style="color:#ebcb8b">&#9654;</span>':''}</td>
331	      <td style="font-size:10px">${l.outcome||''}</td>
332	      <td style="font-size:10px;color:#6a7482">${(l.reason_codes||[]).join(' ')}</td>
333	    </tr>`;
334	  }).join('');
335	}
