362	async function loadPreset() {
363	  const name = document.getElementById('presetSelect').value;
364	  if (!name) return;
365	  try {
366	    const resp = await fetch('/api/presets/'+encodeURIComponent(name));
367	    if (!resp.ok) { setStatus('Error loading preset'); return; }
368	    const cfg = await resp.json();
369	    currentConfig = cfg;
370	    renderParams(cfg);
371	    setStatus(`Preset "${name}" loaded`);
372	    if (document.getElementById('autoRescore').checked) rescore();
373	  } catch(e) { setStatus('Error: '+e.message); }
