377	  const name = prompt('Preset name (alphanumeric, hyphens):');
378	  if (!name || !name.trim()) return;
379	  const params = collectParams();
380	  try {
381	    const resp = await fetch('/api/presets/'+encodeURIComponent(name.trim()), {
